Question: How many consecutive days did the average rmssd in heart_rate_variability across all users increase, starting from 2022-05-29T00:00:00?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_avg AS (
    SELECT DATE(ts) AS date, AVG(rmssd) AS avg_rmssd
    FROM heart_rate_variability
    WHERE ts >= '2022-05-29'
    GROUP BY DATE(ts)
),
consecutive_days AS (
    SELECT date, avg_rmssd,
           @prev_avg := @curr_avg AS prev_avg,
           @curr_avg := avg_rmssd
    FROM daily_avg, (SELECT @curr_avg := NULL) AS init
    ORDER BY date
)
SELECT COUNT(*) AS consecutive_days
FROM consecutive_days
WHERE avg_rmssd > prev_avg;

